            var hig = new HigienizadorLexico();

            int braceLevel = 0;
            int typeBraceLevel = -1;
            string? currentType = null;

            void AddReference(string from, string to, TipoReferencia kind)
            {
                if (from == to) return;
                if (!tipos.Contains(to)) return;

                if (!refs.Any(r => r.FromType == from && r.ToType == to && r.Kind == kind))
                {
                    refs.Add(new ReferenciaInfo(from, to, kind));
                }
            }

            foreach (var line in File.ReadLines(path))
            {
                string clean = hig.CleanLine(line);
                if (string.IsNullOrEmpty(clean)) continue;

                braceLevel += clean.Count(c => c == '{');

                var typeMatch = TypeRegex.Match(clean);
                if (typeMatch.Success)
                {
                    currentType = typeMatch.Groups[2].Value;
                    typeBraceLevel = braceLevel;
                }

                if (clean.Contains("}"))
                {
                    braceLevel -= clean.Count(c => c == '}');

                    if (currentType != null && braceLevel < typeBraceLevel)
                    {
                        currentType = null;
                        typeBraceLevel = -1;
                    }
                }

                if (currentType == null) continue;

                var fromType = currentType!;

                foreach (Match m in NewInstanceRegex.Matches(clean))
                    AddReference(fromType, m.Groups[1].Value, TipoReferencia.Instantiation);

                foreach (Match m in StaticCallRegex.Matches(clean))
                    AddReference(fromType, m.Groups[1].Value, TipoReferencia.StaticCall);

                foreach (Match m in GenericRegex.Matches(clean))
                    AddReference(fromType, m.Groups[1].Value, TipoReferencia.Generic);

                foreach (Match m in TypeofRegex.Matches(clean))
                    AddReference(fromType, m.Groups[1].Value, TipoReferencia.Typeof);

                foreach (Match m in NameofRegex.Matches(clean))
                    AddReference(fromType, m.Groups[1].Value, TipoReferencia.Nameof);

                foreach (Match m in DeclarationRegex.Matches(clean))
                    AddReference(fromType, m.Groups[1].Value, TipoReferencia.Declaration);

                foreach (Match m in WordRegex.Matches(clean))
                    AddReference(fromType, m.Value, TipoReferencia.Mention);
            }

            if (braceLevel != 0)
            {
                warn?.Invoke(
                    $"Desbalanceamento de chaves detectado em '{Path.GetFileName(path)}'. " +
                    $"O escopo de referências pode estar impreciso.");
            }

            return refs;
        }
    }
}

using System;
using System.Collections.Generic;
using System.Diagnostics;
using RefactorScope.Core.Abstractions;
using RefactorScope.Core.Model;
using RefactorScope.Core.Parsing;

namespace RefactorScope.Parsers.Hybrid;

/// <summary>
/// Parser híbrido que orquestra dois parsers diferentes.
/// 
/// Modos disponíveis:
/// 
/// Failover
///     Usa parser primário.
///     Caso falhe ou gere resultado implausível,
///     executa o parser secundário.
///
/// Merge
///     Executa ambos os parsers e combina seus resultados.
///     Regex define estrutura (tipos).
///     Textual enriquece dependências.
/// </summary>
public class HybridParser : IParserCodigo
{
    private readonly IParserCodigo primary;
    private readonly IParserCodigo secondary;
    private readonly HybridMode mode;
    private readonly Action<string>? warn;

    public string Name => $"HybridParser ({mode})";

    public HybridParser(
        IParserCodigo primaryParser,
        IParserCodigo secondaryParser,
        HybridMode mode,
        Action<string>? warn = null)
    {
        primary = primaryParser;
        secondary = secondaryParser;
        this.mode = mode;
        this.warn = warn;
    }

    public IParserResult Parse(
        string rootPath,
        IEnumerable<string>? include = null,
        IEnumerable<string>? exclude = null)
    {
        var stopwatch = Stopwatch.StartNew();

        var primaryResult =
            primary.Parse(rootPath, include, exclude);

        if (mode == HybridMode.Failover)
        {
            if (primaryResult.Status == ParseStatus.Success &&
                primaryResult.IsPlausible)
            {
                stopwatch.Stop();

                warn?.Invoke(
                    $"[Hybrid] Resultado aceito do parser primário ({primary.Name}).");

                return CriarEnvelope(
                    primaryResult,
                    ParseStatus.Success,
                    stopwatch.Elapsed,
                    false);
            }

            warn?.Invoke(
                $"[Hybrid] {primary.Name} falhou ou gerou anomalia. Executando fallback: {secondary.Name}");

            var fallback =
                secondary.Parse(rootPath, include, exclude);

            stopwatch.Stop();

            return CriarEnvelope(
                fallback,
                ParseStatus.FallbackTriggered,
                stopwatch.Elapsed,
                true);
        }

        // -------------------------
        // MERGE MODE
        // -------------------------

        warn?.Invoke(
            "[Hybrid] Modo Merge ativo. Executando parsers...");

        var secondaryResult =
            secondary.Parse(rootPath, include, exclude);

        var merged =
            ModeloMerger.Merge(
                primaryResult.Model!,
                secondaryResult.Model!);

        stopwatch.Stop();

        bool plausible =
            PlausibilityEvaluator.Evaluate(merged);

        warn?.Invoke(
            "[Hybrid] Merge concluído. Modelo enriquecido.");

        return new ParserResult(
            Status: plausible
                ? ParseStatus.Success
                : ParseStatus.PlausibilityWarning,

            IsPlausible: plausible,

            Confidence:
                Math.Max(
                    primaryResult.Confidence,
                    secondaryResult.Confidence),

            ParserName: Name,

            Model: merged,

            UsedFallback: false,

            Stats: new ParserExecutionStats(
                stopwatch.Elapsed,
                0,
                !plausible)
        );
    }

    private IParserResult CriarEnvelope(
        IParserResult inner,
        ParseStatus status,
        TimeSpan time,
        bool usedFallback)
    {
        return new ParserResult(
            Status: status,
            IsPlausible: inner.IsPlausible,
            Confidence: inner.Confidence,
            ParserName: $"{Name} -> {inner.ParserName}",
            Model: inner.Model,
            UsedFallback: usedFallback,
            Stats: new ParserExecutionStats(
                time,
                inner.Stats?.EstimatedMemoryBytes ?? 0,
                !inner.IsPlausible),
            Error: inner.Error);
    }
}

using System;
using System.Collections.Generic;
using System.Diagnostics;
using RefactorScope.Core.Abstractions;
using RefactorScope.Core.Model;
using RefactorScope.Core.Parsing;

namespace RefactorScope.Parsers.Hybrid;

/// <summary>
/// Hybrid Adaptive Parser
///
/// Estratégia:
///
/// 1. Executa parser primário (Regex)
/// 2. Avalia plausibilidade estrutural
/// 3. Caso estrutura esteja fraca:
///       parser secundário recupera TIPOS
/// 4. Caso estrutura esteja boa:
///       parser secundário extrai apenas dependências
///
/// Objetivo:
/// tornar o merge resiliente a falhas do Regex.
///
/// Este modo é ideal para repositórios
/// com código parcialmente inválido
/// ou geração dinâmica de código.
/// </summary>
public class HybridAdaptiveParser : IParserCodigo
{
    private readonly IParserCodigo primary;
    private readonly IParserCodigo secondary;
    private readonly Action<string>? warn;

    public string Name => "HybridParser (Adaptive)";

    public HybridAdaptiveParser(
        IParserCodigo primaryParser,
        IParserCodigo secondaryParser,
        Action<string>? warn = null)
    {
        primary = primaryParser;
        secondary = secondaryParser;
        this.warn = warn;
    }

    public IParserResult Parse(
        string rootPath,
        IEnumerable<string>? include = null,
        IEnumerable<string>? exclude = null)
    {
        var stopwatch = Stopwatch.StartNew();

        warn?.Invoke("[HybridAdaptive] Executando parser primário...");

        var primaryResult =
            primary.Parse(rootPath, include, exclude);

        bool weakStructure =
            primaryResult.Model == null ||
            primaryResult.Model.Tipos.Count < 3;

        if (weakStructure)
        {
            warn?.Invoke(
                "[HybridAdaptive] Estrutura fraca detectada. Recuperando tipos via parser secundário.");
        }
        else
        {
            warn?.Invoke(
                "[HybridAdaptive] Estrutura válida. Extraindo dependências adicionais.");
        }

        var secondaryResult =
            secondary.Parse(rootPath, include, exclude);

        var merged =
            ModeloMerger.Merge(
                primaryResult.Model!,
                secondaryResult.Model!);

        stopwatch.Stop();

        bool plausible =
            PlausibilityEvaluator.Evaluate(merged);

        warn?.Invoke("[HybridAdaptive] Merge adaptativo concluído.");

        return new ParserResult(
            Status: plausible
                ? ParseStatus.Success
                : ParseStatus.PlausibilityWarning,

            IsPlausible: plausible,

            Confidence:
                Math.Max(
                    primaryResult.Confidence,
                    secondaryResult.Confidence),

            ParserName: Name,

            Model: merged,

            UsedFallback: false,

            Stats: new ParserExecutionStats(
                stopwatch.Elapsed,
                0,
                !plausible)
        );
    }
}

using System;
using System.Collections.Generic;
using System.Diagnostics;
using RefactorScope.Core.Abstractions;
using RefactorScope.Core.Model;
using RefactorScope.Core.Parsing;

namespace RefactorScope.Parsers.Hybrid;

/// <summary>
/// Hybrid Incremental Parser
///
/// Estratégia:
///
/// 1. Executa parser primário (Regex)
/// 2. Avalia qualidade estrutural
/// 3. Caso o modelo já seja suficientemente completo:
///       retorna imediatamente
///
/// 4. Caso contrário:
///       executa parser secundário
///       e realiza merge.
///
/// Objetivo:
/// reduzir custo computacional.
///
/// Ideal para repositórios grandes
/// onde Regex já fornece boa cobertura.
/// </summary>
public class HybridIncrementalParser : IParserCodigo
{
    private readonly IParserCodigo primary;
    private readonly IParserCodigo secondary;
    private readonly Action<string>? warn;

    public string Name => "HybridParser (Incremental)";

    public HybridIncrementalParser(
        IParserCodigo primaryParser,
        IParserCodigo secondaryParser,
        Action<string>? warn = null)
    {
        primary = primaryParser;
        secondary = secondaryParser;
        this.warn = warn;
    }

    public IParserResult Parse(
        string rootPath,
        IEnumerable<string>? include = null,
        IEnumerable<string>? exclude = null)
    {
        var stopwatch = Stopwatch.StartNew();

        warn?.Invoke("[HybridIncremental] Executando parser primário...");

        var primaryResult =
            primary.Parse(rootPath, include, exclude);

        if (primaryResult.Model != null &&
            primaryResult.Model.Referencias.Count > 20)
        {
            stopwatch.Stop();

            warn?.Invoke(
                "[HybridIncremental] Modelo primário suficiente. Skip do parser secundário.");

            return new ParserResult(
                Status: primaryResult.Status,
                IsPlausible: primaryResult.IsPlausible,
                Confidence: primaryResult.Confidence,
                ParserName: "HybridParser (Incremental → Regex)",
                Model: primaryResult.Model,
                UsedFallback: false,
                Stats: primaryResult.Stats,
                Error: primaryResult.Error
            );
        }

        warn?.Invoke(
            "[HybridIncremental] Modelo incompleto. Executando parser secundário.");

        var secondaryResult =
            secondary.Parse(rootPath, include, exclude);

        var merged =
            ModeloMerger.Merge(
                primaryResult.Model!,
                secondaryResult.Model!);

        stopwatch.Stop();

        bool plausible =
            PlausibilityEvaluator.Evaluate(merged);

        warn?.Invoke("[HybridIncremental] Merge incremental concluído.");

        return new ParserResult(
            Status: plausible
                ? ParseStatus.Success
                : ParseStatus.PlausibilityWarning,

            IsPlausible: plausible,

            Confidence:
                Math.Max(
                    primaryResult.Confidence,
                    secondaryResult.Confidence),

            ParserName: Name,

            Model: merged,

            UsedFallback: false,

            Stats: new ParserExecutionStats(
                stopwatch.Elapsed,
                0,
                !plausible)
        );
    }
}

using System.Linq;
using RefactorScope.Core.Model;

namespace RefactorScope.Parsers.Hybrid;

/// <summary>
/// Responsável por combinar dois ModeloEstrutural garantindo
/// integridade do grafo de tipos.
/// </summary>
public static class ModeloMerger
{
    public static ModeloEstrutural Merge(ModeloEstrutural regexModel, ModeloEstrutural textualModel)
    {
        var tipos = regexModel.Tipos;
        var arquivos = regexModel.Arquivos;

        // Apenas tipos confirmados pelo Regex são aceitos
        var tiposValidados = tipos.Select(t => t.Name).ToHashSet();

        var referenciasCombinadas =
            regexModel.Referencias
            .Concat(textualModel.Referencias)
            .Where(r =>
                tiposValidados.Contains(r.FromType) &&
                tiposValidados.Contains(r.ToType))
            .DistinctBy(r => new { r.FromType, r.ToType, r.Kind })
            .ToList();

        // Reinjeta referências no grafo interno
        foreach (var tipo in tipos)
        {
            var refsDoTipo =
                referenciasCombinadas
                .Where(r => r.FromType == tipo.Name)
                .ToList();

            typeof(TipoInfo)
                .GetField("<References>k__BackingField",
                    System.Reflection.BindingFlags.Instance |
                    System.Reflection.BindingFlags.NonPublic)
                ?.SetValue(tipo, refsDoTipo);
        }

        return new ModeloEstrutural(
            regexModel.RootPath,
            arquivos,
            tipos,
            referenciasCombinadas);
    }
}
